import{_ as e,o as i,c as d,an as r}from"./chunks/framework.u9TpJulR.js";const p=JSON.parse('{"title":"Concepts: composition verbs and primitives","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/concepts.md","filePath":"getting-started/concepts.md","lastUpdated":null}'),a={name:"getting-started/concepts.md"};function o(l,t,s,n,c,g){return i(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="concepts" tabindex="-1">Concepts: composition verbs and primitives <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts: composition verbs and primitives {#concepts}&quot;">​</a></h1><p>A composed distribution is a multi-state event process: named events linked by delays, wired into a tree. This page maps the modelling concepts to the verbs that build them, so you can find the right primitive by intent before reading the worked examples in <a href="/previews/PR206/getting-started/tutorials/composing-distributions#composing-distributions">Composing distributions</a>.</p><h2 id="The-layers" tabindex="-1">The layers <a class="header-anchor" href="#The-layers" aria-label="Permalink to &quot;The layers {#The-layers}&quot;">​</a></h2><p>The package has four layers, each building on the one before.</p><ul><li><p><strong>Leaves</strong> are any <code>Distributions.jl</code> <code>UnivariateDistribution</code>, used directly as the per-event delays. A leaf can also resolve later: a <a href="/previews/PR206/lib/public#ComposedDistributions.Varying"><code>Varying</code></a> leaf maps an observed covariate to a distribution, and an <a href="/previews/PR206/lib/public#ComposedDistributions.Uncertain"><code>Uncertain</code></a> leaf carries distribution-valued parameters.</p></li><li><p><strong>Composers</strong> wire named leaves into an event tree (<a href="/previews/PR206/lib/public#ComposedDistributions.compose"><code>compose</code></a> and the five composers).</p></li><li><p><strong>Combination and lowering</strong> join or collapse whole delays (<code>convolved</code>, <code>difference</code>, <a href="/previews/PR206/lib/public#ComposedDistributions.observed_distribution"><code>observed_distribution</code></a>).</p></li><li><p><strong>Parameters and edits</strong> read and reshape an assembled tree (<a href="/previews/PR206/lib/public#ComposedDistributions.params_table"><code>params_table</code></a>, <a href="/previews/PR206/lib/public#ComposedDistributions.build_priors"><code>build_priors</code></a>, <a href="./@ref"><code>update</code></a>, <a href="/previews/PR206/lib/public#ComposedDistributions.prune"><code>prune</code></a>, <a href="/previews/PR206/lib/public#ComposedDistributions.splice"><code>splice</code></a>).</p></li></ul><h2 id="The-verb-map" tabindex="-1">The verb map <a class="header-anchor" href="#The-verb-map" aria-label="Permalink to &quot;The verb map {#The-verb-map}&quot;">​</a></h2><p>The verbs fall into five families, listed here as verb, what it does, and what it returns.</p><p><strong>Structural composition</strong> wires named branches into a tree.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Verb</th><th style="text-align:right;">What it does</th><th style="text-align:right;">Returns</th></tr></thead><tbody><tr><td style="text-align:right;"><code>compose</code></td><td style="text-align:right;">lowers a NamedTuple, table or matrix to the stack</td><td style="text-align:right;">a composer</td></tr><tr><td style="text-align:right;"><code>sequential</code></td><td style="text-align:right;">a conjunctive chain, where steps add up</td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Sequential"><code>Sequential</code></a></td></tr><tr><td style="text-align:right;"><code>parallel</code></td><td style="text-align:right;">independent branches off one shared origin</td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Parallel"><code>Parallel</code></a></td></tr><tr><td style="text-align:right;"><code>resolve</code></td><td style="text-align:right;">one outcome occurs by a fixed probability</td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Resolve"><code>Resolve</code></a></td></tr><tr><td style="text-align:right;"><code>compete</code></td><td style="text-align:right;">racing hazards, the first to fire wins</td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Compete"><code>Compete</code></a></td></tr><tr><td style="text-align:right;"><code>choose</code></td><td style="text-align:right;">a data field picks the branch</td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Choose"><code>Choose</code></a></td></tr><tr><td style="text-align:right;"><code>shared</code></td><td style="text-align:right;">tags a leaf as a tied parameter group at build time</td><td style="text-align:right;">a tied leaf</td></tr><tr><td style="text-align:right;"><code>tie</code></td><td style="text-align:right;">ties leaves at named paths into one parameter group</td><td style="text-align:right;">a tied tree</td></tr><tr><td style="text-align:right;"><code>@events</code></td><td style="text-align:right;">a readable <code>→</code>/<code>|</code>/<code>&amp;</code> operator diagram of a topology, structure only, filled later with <code>update</code></td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.EventSkeleton"><code>EventSkeleton</code></a></td></tr></tbody></table><p><code>@events</code> is worked through in <a href="/previews/PR206/getting-started/tutorials/event-skeletons#event-skeletons">Event skeletons</a>.</p><p><strong>Combination and lowering</strong> joins or collapses whole delays.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Verb</th><th style="text-align:right;">What it does</th><th style="text-align:right;">Returns</th></tr></thead><tbody><tr><td style="text-align:right;"><code>convolved</code></td><td style="text-align:right;">the sum <code>X + Y</code></td><td style="text-align:right;"><code>Convolved</code></td></tr><tr><td style="text-align:right;"><code>difference</code></td><td style="text-align:right;">the dual <code>X - Y</code></td><td style="text-align:right;"><code>Difference</code></td></tr><tr><td style="text-align:right;"><code>as_mixture</code></td><td style="text-align:right;">the mixture view of a one_of node</td><td style="text-align:right;">a <code>MixtureModel</code></td></tr><tr><td style="text-align:right;"><code>observed_distribution</code></td><td style="text-align:right;">collapses a chain to its convolved total</td><td style="text-align:right;">a convolved leaf</td></tr></tbody></table><p><strong>Parameters</strong> read and prior the free parameters.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Verb</th><th style="text-align:right;">What it does</th><th style="text-align:right;">Returns</th></tr></thead><tbody><tr><td style="text-align:right;"><code>params_table</code></td><td style="text-align:right;">the flat free-parameter inventory</td><td style="text-align:right;">a Tables.jl table</td></tr><tr><td style="text-align:right;"><code>build_priors</code></td><td style="text-align:right;">support-derived default priors from that table</td><td style="text-align:right;">a nested prior <code>NamedTuple</code></td></tr><tr><td style="text-align:right;"><code>default_prior</code></td><td style="text-align:right;">the default prior for one parameter row</td><td style="text-align:right;">a <code>Distribution</code></td></tr><tr><td style="text-align:right;"><code>param_priors</code></td><td style="text-align:right;"><code>params_table</code> + <code>build_priors</code> in one call, for <code>uncertain(tree)</code> (bare)</td><td style="text-align:right;">a nested prior <code>NamedTuple</code></td></tr><tr><td style="text-align:right;"><code>uncertain(tree, ...)</code></td><td style="text-align:right;">promote one or more free parameters of an existing tree; bare <code>uncertain(tree)</code> promotes all</td><td style="text-align:right;">a tree</td></tr></tbody></table><p>See <a href="/previews/PR206/getting-started/inference#inference">Fitting a composed distribution</a> for how these feed the estimation pipeline.</p><p><strong>Reading and editing</strong> inspect or reshape an assembled tree.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Verb</th><th style="text-align:right;">What it does</th><th style="text-align:right;">Returns</th></tr></thead><tbody><tr><td style="text-align:right;"><code>event</code> / <code>event_names</code> / <code>event_tree</code></td><td style="text-align:right;">fetch a child or the record key names</td><td style="text-align:right;">a node, leaf or names</td></tr><tr><td style="text-align:right;"><code>mean</code> / <code>var</code></td><td style="text-align:right;">the composed marginal moments</td><td style="text-align:right;">a number or <code>NamedTuple</code></td></tr><tr><td style="text-align:right;"><code>update</code></td><td style="text-align:right;">replaces parameter values or whole nodes</td><td style="text-align:right;">a same-shape tree</td></tr><tr><td style="text-align:right;"><code>prune</code> / <code>splice</code></td><td style="text-align:right;">drops or inserts a branch</td><td style="text-align:right;">an edited tree</td></tr></tbody></table><p><strong>Deferred leaves</strong> hold a distribution that resolves later. <code>varying</code> and <code>uncertain</code> are the two cases of one idea: a leaf that is a <em>map to a distribution</em> rather than a fixed distribution, delegating silently to a fallback until it is resolved. They differ only in what indexes the map — <code>varying</code> an <strong>observed</strong> covariate (time, stratum) resolved by <code>instantiate</code>, <code>uncertain</code> a <strong>latent</strong> parameter draw (with a prior) resolved by <code>rand</code> or collapsed by <code>update</code> — and they share one resolution walk, so a leaf can be both at once.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Verb</th><th style="text-align:right;">What it does</th><th style="text-align:right;">Returns</th></tr></thead><tbody><tr><td style="text-align:right;"><code>varying</code> / <code>Context</code> / <code>instantiate</code></td><td style="text-align:right;">an observed covariate picks the leaf</td><td style="text-align:right;">a resolved tree</td></tr><tr><td style="text-align:right;"><code>has_varying</code></td><td style="text-align:right;">whether any un-instantiated leaf remains</td><td style="text-align:right;">a <code>Bool</code></td></tr><tr><td style="text-align:right;"><code>uncertain</code></td><td style="text-align:right;">distribution-valued parameters that act as priors</td><td style="text-align:right;">an uncertain leaf</td></tr><tr><td style="text-align:right;"><code>has_uncertain</code></td><td style="text-align:right;">whether any uncertain leaf remains</td><td style="text-align:right;">a <code>Bool</code></td></tr></tbody></table><p>The deferred-leaf verbs are worked through in <a href="/previews/PR206/getting-started/tutorials/strata-uncertainty#strata-uncertainty">Multi-strata trees and parameter uncertainty</a>.</p><h2 id="Concept-to-primitive" tabindex="-1">Concept to primitive <a class="header-anchor" href="#Concept-to-primitive" aria-label="Permalink to &quot;Concept to primitive {#Concept-to-primitive}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Modelling concept</th><th style="text-align:right;">Primitive</th><th style="text-align:right;">What it builds</th></tr></thead><tbody><tr><td style="text-align:right;">Steps in series (a chain)</td><td style="text-align:right;"><code>sequential</code> / <code>compose</code> with a <code>Vector</code> value</td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Sequential"><code>Sequential</code></a></td></tr><tr><td style="text-align:right;">Branches off one shared origin</td><td style="text-align:right;"><code>parallel</code> / <code>compose</code> with a <code>NamedTuple</code></td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Parallel"><code>Parallel</code></a></td></tr><tr><td style="text-align:right;">One outcome by fixed probability</td><td style="text-align:right;"><code>resolve</code></td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Resolve"><code>Resolve</code></a></td></tr><tr><td style="text-align:right;">Racing outcomes (first to fire wins)</td><td style="text-align:right;"><code>compete</code></td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Compete"><code>Compete</code></a></td></tr><tr><td style="text-align:right;">A data field selects the sub-model</td><td style="text-align:right;"><code>choose</code></td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Choose"><code>Choose</code></a></td></tr><tr><td style="text-align:right;">Tie a leaf across branches</td><td style="text-align:right;"><code>shared</code> / <code>tie</code></td><td style="text-align:right;">one shared parameter group</td></tr><tr><td style="text-align:right;">A topology reused across pathogens or settings</td><td style="text-align:right;"><code>@events</code> + <code>update(skeleton; ...)</code></td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.EventSkeleton"><code>EventSkeleton</code></a></td></tr><tr><td style="text-align:right;">Sum of two independent delays</td><td style="text-align:right;"><code>convolved</code></td><td style="text-align:right;"><code>Convolved</code></td></tr><tr><td style="text-align:right;">Difference of two delays</td><td style="text-align:right;"><code>difference</code></td><td style="text-align:right;"><code>Difference</code></td></tr><tr><td style="text-align:right;">Mixture view of a one_of node</td><td style="text-align:right;"><code>as_mixture</code></td><td style="text-align:right;">a <code>MixtureModel</code></td></tr><tr><td style="text-align:right;">Collapse a chain to its total</td><td style="text-align:right;"><code>observed_distribution</code></td><td style="text-align:right;">the convolved marginal</td></tr><tr><td style="text-align:right;">The free-parameter inventory</td><td style="text-align:right;"><code>params_table</code></td><td style="text-align:right;">a Tables.jl table</td></tr><tr><td style="text-align:right;">Support-derived priors</td><td style="text-align:right;"><code>build_priors</code></td><td style="text-align:right;">a nested prior <code>NamedTuple</code></td></tr><tr><td style="text-align:right;">Read a child or descend a path</td><td style="text-align:right;"><code>event</code></td><td style="text-align:right;">a node or leaf</td></tr><tr><td style="text-align:right;">Flat / nested event names</td><td style="text-align:right;"><code>event_names</code> / <code>event_tree</code></td><td style="text-align:right;">the record key names</td></tr><tr><td style="text-align:right;">Replace values or whole nodes</td><td style="text-align:right;"><code>update</code></td><td style="text-align:right;">a same-shape tree</td></tr><tr><td style="text-align:right;">Drop or insert a branch</td><td style="text-align:right;"><code>prune</code> / <code>splice</code></td><td style="text-align:right;">an edited tree</td></tr><tr><td style="text-align:right;">A leaf that varies with a covariate</td><td style="text-align:right;"><code>varying</code>, resolved by <code>instantiate</code></td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Varying"><code>Varying</code></a></td></tr><tr><td style="text-align:right;">A leaf with parameter uncertainty</td><td style="text-align:right;"><code>uncertain</code>, collapsed by <code>update</code></td><td style="text-align:right;"><a href="/previews/PR206/lib/public#ComposedDistributions.Uncertain"><code>Uncertain</code></a></td></tr><tr><td style="text-align:right;">Guard a fitting loop against unresolved leaves</td><td style="text-align:right;"><code>has_varying</code> / <code>has_uncertain</code></td><td style="text-align:right;">a <code>Bool</code></td></tr></tbody></table><p>Read <a href="/previews/PR206/getting-started/tutorials/composing-distributions#composing-distributions">Composing distributions</a> for each verb worked through end to end.</p>',23)])])}const y=e(a,[["render",o]]);export{p as __pageData,y as default};
